.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
}

/* Channel Sidebar */
.channel-sidebar {
    width: 20%;
    min-width: 200px;
    background: #2c2f33;
    color: #dcddde;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #202225;
}

.sidebar-title {
    padding: 16px;
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
